#include<bits/stdc++.h>
using namespace std;
int n,max1=0,max2=0,a[1005];
int main()
{
    cin>>n;
    for(int i=1;i<=pow(2,n);i++)
    {
        cin>>a[i];
        if(i<=pow(2,n-1)&&a[max1]<a[i]) max1=i;
        else if(i>pow(2,n-1)&&a[max2]<a[i]) max2=i;
    }
    if(a[max1]>a[max2]) cout<<max2;
    else cout<<max1;
    return 0;
}
